import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Product, Order, StoreConfig, DashboardStats, Coupon, Member, User, RestockRequest, OrderStatus, Role, ViewState } from '../types';
import { syncToGoogleSheet, fetchFromCloud } from '../services/googleSheetsService';

interface StoreContextType {
  products: Product[];
  orders: Order[];
  coupons: Coupon[];
  members: Member[];
  users: User[];
  roles: Role[];
  currentUser: User | null;
  restockRequests: RestockRequest[];
  storeConfig: StoreConfig;
  addProduct: (product: Product) => void;
  updateProduct: (product: Product) => void;
  deleteProduct: (id: string) => void;
  addOrder: (order: Order) => void;
  deleteOrder: (orderId: string) => void;
  updateOrderStatus: (orderId: string, status: OrderStatus) => void;
  addCoupon: (coupon: Coupon) => void;
  updateCoupon: (coupon: Coupon) => void;
  deleteCoupon: (code: string) => void;
  addMember: (member: Member) => void;
  updateMember: (member: Member) => void;
  deleteMember: (id: string) => void;
  addUser: (user: User) => void;
  updateUser: (user: User) => void;
  deleteUser: (id: string) => void;
  addRole: (role: Role) => void;
  updateRole: (role: Role) => void;
  deleteRole: (id: string) => void;
  login: (email: string, pinOrPass: string) => boolean;
  logout: () => void;
  addRestockRequest: (request: RestockRequest) => void;
  updateConfig: (config: StoreConfig) => void;
  stats: DashboardStats;
  refreshStats: () => void;
  currentThemeColorHex: string; 
  pullFromCloud: () => Promise<void>;
  pushToCloud: () => Promise<void>;
  isSyncing: boolean;
}

const STORAGE_KEYS = {
  PRODUCTS: 'novapos_products',
  ORDERS: 'novapos_orders',
  COUPONS: 'novapos_coupons',
  MEMBERS: 'novapos_members',
  USERS: 'novapos_users',
  ROLES: 'novapos_roles',
  CONFIG: 'novapos_config',
  SESSION: 'novapos_session'
};

const THEME_PALETTES: Record<string, Record<string, string>> = {
  blue: { 50: '#eff6ff', 100: '#dbeafe', 200: '#bfdbfe', 300: '#93c5fd', 400: '#60a5fa', 500: '#3b82f6', 600: '#2563eb', 700: '#1d4ed8', 800: '#1e40af', 900: '#1e3a8a', 950: '#172554' },
  purple: { 50: '#faf5ff', 100: '#f3e8ff', 200: '#e9d5ff', 300: '#d8b4fe', 400: '#c084fc', 500: '#a855f7', 600: '#9333ea', 700: '#7e22ce', 800: '#6b21a8', 900: '#581c87', 950: '#3b0764' },
  green: { 50: '#f0fdf4', 100: '#dcfce7', 200: '#bbf7d0', 300: '#86efac', 400: '#4ade80', 500: '#22c55e', 600: '#16a34a', 700: '#15803d', 800: '#166534', 900: '#14532d', 950: '#052e16' },
  rose: { 50: '#fff1f2', 100: '#ffe4e6', 200: '#fecdd3', 300: '#fda4af', 400: '#fb7185', 500: '#f43f5e', 600: '#e11d48', 700: '#be123c', 800: '#9f1239', 900: '#881337', 950: '#4c0519' },
  orange: { 50: '#fff7ed', 100: '#ffedd5', 200: '#fed7aa', 300: '#fdba74', 400: '#fb923c', 500: '#f97316', 600: '#ea580c', 700: '#c2410c', 800: '#9a3412', 900: '#7c2d12', 950: '#431407' },
  slate: { 50: '#f8fafc', 100: '#f1f5f9', 200: '#e2e8f0', 300: '#cbd5e1', 400: '#94a3b8', 500: '#64748b', 600: '#475569', 700: '#334155', 800: '#1e293b', 900: '#0f172a', 950: '#020617' }
};

const defaultStoreConfig: StoreConfig = {
  name: "โนว่า คาเฟ่ แอนด์ รีเทล",
  address: "123 ถ.สุขุมวิท เขตวัฒนา กรุงเทพฯ 10110",
  taxRate: 7,
  currency: "฿",
  logoUrl: "",
  themeColor: "blue",
  googleSheetsUrl: "",
  lowStockThreshold: 10,
  paymentMethods: { cash: true, promptpay: true, truemoney: true, transfer: true, ewallet: true, card: true },
  loyaltySystem: 'points', 
  pointEarningRate: 25, 
  pointRedemptionRate: 10, 
  stampMinSpend: 50, 
  stampsPerReward: 10, 
  stampRewardValue: 50, 
  adminPin: "1234",
  queueEnabled: true,
  queueStepReadyEnabled: true
};

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.PRODUCTS) || '[]'));
  const [orders, setOrders] = useState<Order[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.ORDERS) || '[]'));
  const [coupons, setCoupons] = useState<Coupon[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.COUPONS) || '[]'));
  const [members, setMembers] = useState<Member[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.MEMBERS) || '[]'));
  const [users, setUsers] = useState<User[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.USERS) || '[]'));
  const [roles, setRoles] = useState<Role[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.ROLES) || '[]'));
  const [storeConfig, setStoreConfig] = useState<StoreConfig>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.CONFIG) || JSON.stringify(defaultStoreConfig)));

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.SESSION);
    return saved ? JSON.parse(saved) : null;
  });

  const [restockRequests, setRestockRequests] = useState<RestockRequest[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const [stats, setStats] = useState<DashboardStats>({
    todaySales: 0, todayCost: 0, todayProfit: 0, monthlyProfit: 0,
    orderCount: 0, lowStockCount: 0, topProducts: []
  });

  const pullFromCloud = async () => {
    if (!storeConfig.googleSheetsUrl) return;
    setIsSyncing(true);
    try {
      const cloudData = await fetchFromCloud(storeConfig.googleSheetsUrl);
      if (cloudData) {
        if (cloudData.products) setProducts(cloudData.products);
        if (cloudData.members) setMembers(cloudData.members);
        if (cloudData.users) setUsers(cloudData.users);
        if (cloudData.orders) {
          const formatted = cloudData.orders.map((o: any) => ({
            ...o,
            items: typeof (o.items_json || o.items) === 'string' 
              ? JSON.parse(o.items_json || o.items) 
              : (o.items_json || o.items || [])
          }));
          setOrders(formatted);
        }
        if (cloudData.config) setStoreConfig(prev => ({ ...prev, ...cloudData.config }));
      }
    } finally {
      setIsSyncing(false);
    }
  };

  const pushToCloud = async () => {
    if (!storeConfig.googleSheetsUrl) return;
    setIsSyncing(true);
    try {
      await syncToGoogleSheet('SYNC_ALL', {
        products, members, users, config: storeConfig
      }, storeConfig.googleSheetsUrl);
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
    localStorage.setItem(STORAGE_KEYS.ORDERS, JSON.stringify(orders));
    localStorage.setItem(STORAGE_KEYS.MEMBERS, JSON.stringify(members));
    localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users));
    localStorage.setItem(STORAGE_KEYS.ROLES, JSON.stringify(roles));
    localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(storeConfig));

    const palette = THEME_PALETTES[storeConfig.themeColor] || THEME_PALETTES.blue;
    Object.entries(palette).forEach(([shade, hex]) => {
      document.documentElement.style.setProperty(`--color-primary-${shade}`, hex);
    });
  }, [products, orders, members, users, roles, storeConfig]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem(STORAGE_KEYS.SESSION, JSON.stringify(currentUser));
    } else {
      localStorage.removeItem(STORAGE_KEYS.SESSION);
    }
  }, [currentUser]);

  const refreshStats = () => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];
    const monthStr = now.toISOString().slice(0, 7);
    const todayOrders = orders.filter(o => o.timestamp.startsWith(todayStr));
    const monthlyOrders = orders.filter(o => o.timestamp.startsWith(monthStr));
    const calculateOrderCost = (order: Order) => Array.isArray(order.items) ? order.items.reduce((sum, item) => sum + (item.costPrice * item.quantity), 0) : 0;
    const todaySales = todayOrders.reduce((sum, o) => sum + o.total, 0);
    const todayCost = todayOrders.reduce((sum, o) => sum + calculateOrderCost(o), 0);
    const monthlySales = monthlyOrders.reduce((sum, o) => sum + o.total, 0);
    const monthlyCost = monthlyOrders.reduce((sum, o) => sum + calculateOrderCost(o), 0);
    setStats(prev => ({ 
      ...prev, todaySales, todayCost, todayProfit: todaySales - todayCost, 
      monthlyProfit: monthlySales - monthlyCost, orderCount: todayOrders.length, 
      lowStockCount: products.filter(p => p.stock < storeConfig.lowStockThreshold).length 
    }));
  };

  useEffect(() => { refreshStats(); }, [orders, products, storeConfig.lowStockThreshold]);

  const addOrder = (order: Order) => {
    const finalOrder = { ...order, cashierName: currentUser?.name || 'พนักงานขาย' };
    const updatedProducts = products.map(p => {
      const soldItem = finalOrder.items.find(i => i.id === p.id);
      return soldItem ? { ...p, stock: Math.max(0, p.stock - soldItem.quantity) } : p;
    });
    setProducts(updatedProducts);
    setOrders(prev => [finalOrder, ...prev]);

    if (storeConfig.googleSheetsUrl) {
      const readableItems = finalOrder.items.map(i => `${i.name} x${i.quantity}`).join(', ');
      const orderForSync = { 
        ...finalOrder, 
        items: readableItems, 
        items_json: JSON.stringify(finalOrder.items) 
      };
      syncToGoogleSheet('ADD_ORDER', orderForSync, storeConfig.googleSheetsUrl, updatedProducts);
    }
  };

  const deleteOrder = (orderId: string) => {
    const orderToDelete = orders.find(o => o.id === orderId);
    if (!orderToDelete) return;
    const updatedProducts = products.map(p => {
      const returnedItem = Array.isArray(orderToDelete.items) ? orderToDelete.items.find(i => i.id === p.id) : null;
      return returnedItem ? { ...p, stock: p.stock + returnedItem.quantity } : p;
    });
    setProducts(updatedProducts);
    setOrders(prev => prev.filter(o => o.id !== orderId));
    if (storeConfig.googleSheetsUrl) {
      syncToGoogleSheet('DELETE_ORDER', { id: orderId }, storeConfig.googleSheetsUrl, updatedProducts);
    }
  };

  const login = (email: string, pinOrPass: string) => {
    // REAL ADMIN CREDENTIALS
    if (email === 'sahakorn.dbs@gmail.com' && pinOrPass === 'sahakorn1122') {
      setCurrentUser({ id: 'admin', name: 'สหกรณ์ DBS', email, roleId: 'admin' });
      return true;
    }
    const user = users.find(u => u.email === email);
    if (user && user.password === pinOrPass) { 
      setCurrentUser(user); 
      return true; 
    }
    return false;
  };

  return (
    <StoreContext.Provider value={{ 
      products, orders, coupons, members, users, roles, currentUser, restockRequests, storeConfig, 
      addProduct: (p) => setProducts(prev => [...prev, p]), 
      updateProduct: (p) => setProducts(prev => prev.map(old => old.id === p.id ? p : old)), 
      deleteProduct: (id) => setProducts(prev => prev.filter(p => p.id !== id)),
      addOrder, deleteOrder, updateOrderStatus: (id, status) => {
        setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
      }, 
      addCoupon: (c) => setCoupons(prev => [...prev, c]), 
      updateCoupon: (c) => setCoupons(prev => prev.map(old => old.code === c.code ? c : old)), 
      deleteCoupon: (code) => setCoupons(prev => prev.filter(c => c.code !== code)),
      addMember: (m) => setMembers(prev => [...prev, m]), 
      updateMember: (m) => setMembers(prev => prev.map(old => old.id === m.id ? m : old)), 
      deleteMember: (id) => setMembers(prev => prev.filter(m => m.id !== id)),
      addUser: (u) => setUsers(prev => [...prev, u]), 
      updateUser: (u) => setUsers(prev => prev.map(old => old.id === u.id ? u : old)), 
      deleteUser: (id) => setUsers(prev => prev.filter(u => u.id !== id)),
      addRole: (r) => setRoles(prev => [...prev, r]), 
      updateRole: (r) => setRoles(prev => prev.map(old => old.id === r.id ? r : old)), 
      deleteRole: (id) => setRoles(prev => prev.filter(r => r.id !== id)), 
      login, logout: () => setCurrentUser(null),
      addRestockRequest: (r) => setRestockRequests(prev => [...prev, r]), 
      updateConfig: setStoreConfig, stats, refreshStats, 
      currentThemeColorHex: (THEME_PALETTES[storeConfig.themeColor] || THEME_PALETTES.blue)[600],
      pullFromCloud, pushToCloud, isSyncing
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within a StoreProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { Store, AlertCircle, ShieldCheck, CheckSquare, Square } from 'lucide-react';
import { useStore } from '../context/StoreContext';

const REMEMBER_KEY = 'novapos_remembered_credentials';

const Login: React.FC = () => {
  const { login } = useStore();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem(REMEMBER_KEY);
    if (saved) {
      try {
        const { email: savedEmail, password: savedPassword } = JSON.parse(saved);
        setEmail(savedEmail || '');
        setPassword(savedPassword || '');
        setRememberMe(true);
      } catch (e) {
        console.error("Failed to parse remembered credentials");
      }
    }
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanEmail = email.toLowerCase().trim();
    const success = login(cleanEmail, password);

    if (success) {
      if (rememberMe) {
        localStorage.setItem(REMEMBER_KEY, JSON.stringify({ email: cleanEmail, password }));
      } else {
        localStorage.removeItem(REMEMBER_KEY);
      }
    } else {
      setError('อีเมลหรือรหัสผ่านไม่ถูกต้อง กรุณาลองใหม่');
    }
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 items-center justify-center p-4 relative overflow-hidden">
      {/* Background Ambience */}
      <div className="absolute top-[-15%] left-[-10%] w-[50%] h-[50%] bg-primary-600 rounded-full blur-[120px] opacity-10 animate-pulse"></div>
      <div className="absolute bottom-[-15%] right-[-10%] w-[50%] h-[50%] bg-indigo-600 rounded-full blur-[120px] opacity-10 animate-pulse"></div>

      <div className="bg-slate-900/40 backdrop-blur-3xl border border-white/5 p-10 rounded-[3rem] shadow-2xl w-full max-w-md text-white z-10 relative group">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-primary-500 to-transparent opacity-30"></div>

        <div className="flex flex-col items-center mb-10">
          <div className="w-20 h-20 bg-gradient-to-tr from-primary-600 to-indigo-600 rounded-3xl flex items-center justify-center mb-6 shadow-2xl shadow-primary-900/40 transition-transform hover:scale-105">
            <Store size={40} className="text-white" />
          </div>
          <h1 className="text-4xl font-black tracking-tighter mb-2">DBS POS</h1>
          <p className="text-slate-400 text-center font-medium opacity-80 uppercase tracking-widest text-[10px]">Secure Retail Management</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-5">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 p-4 rounded-2xl flex items-center gap-3 text-red-400 text-sm animate-in fade-in slide-in-from-top-2 duration-300">
                <AlertCircle size={18} /> {error}
            </div>
          )}

          <div className="space-y-2">
            <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Account Email</label>
            <input 
              type="email" 
              required
              className="w-full bg-slate-800/40 border border-white/10 rounded-2xl p-4 text-white placeholder-slate-600 focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all font-medium"
              placeholder="sahakorn.dbs@gmail.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Secure Password</label>
            <input 
              type="password" 
              required
              className="w-full bg-slate-800/40 border border-white/10 rounded-2xl p-4 text-white placeholder-slate-600 focus:ring-2 focus:ring-primary-500 focus:outline-none transition-all font-medium"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <div className="flex items-center justify-between px-1">
             <button 
                type="button" 
                onClick={() => setRememberMe(!rememberMe)}
                className="flex items-center gap-2 group/check"
             >
                <div className={`transition-colors ${rememberMe ? 'text-primary-500' : 'text-slate-600 group-hover/check:text-slate-400'}`}>
                   {rememberMe ? <CheckSquare size={20} /> : <Square size={20} />}
                </div>
                <span className="text-xs font-bold text-slate-400 group-hover/check:text-slate-300 transition-colors">จดจำรหัสผ่าน</span>
             </button>

             <span className="text-[10px] font-bold text-slate-600 uppercase tracking-tight">V2.4 Secure</span>
          </div>

          <button 
            type="submit" 
            className="w-full bg-primary-600 hover:bg-primary-500 text-white font-black py-4 rounded-2xl shadow-xl shadow-primary-950 transition-all active:scale-[0.97] mt-8 flex items-center justify-center gap-2 group/btn"
          >
            <ShieldCheck size={20} className="group-hover/btn:scale-110 transition-transform" />
            เข้าสู่ระบบ
          </button>
        </form>

        <div className="mt-12 pt-8 border-t border-white/5 text-center">
            <p className="text-[10px] text-slate-600 font-black uppercase tracking-widest">DBS POS • 2024 Version</p>
        </div>
      </div>
    </div>
  );
};

export default Login;
